package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Text   template.HTML
}

var comments = []Comment{
	{Author: "Alice", Text: "<b>Hello, world!</b>"},
	{Author: "Bob", Text: "<i>This is italic</i>"},
}

var tmpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
	<title>User Comments</title>
</head>
<body>
	<h1>Comments</h1>
	{{range .}}
		<div>
			<strong>{{.Author}}:</strong> {{.Text}}
		</div>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl.Execute(w, comments)
}

func main() {
	http.HandleFunc("/", commentsHandler)
	http.ListenAndServe(":8080", nil)
}